var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……후우. 해냈나.","JPN":"……ふう。やり遂げたのか。","ENG":"...*Sigh...* It is done.","TWN":"……呼，做到了嗎。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"침식파가 유입되던 근원은 소실되었어. 다들 고맙네.","JPN":"侵食波が流入されていた根源は消えた。みんな、ありがとう。","ENG":"The source of the Corruption ray has disappeared shut.","TWN":"侵蝕波流入的根源消失了，謝謝大家。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"도주한 망령들은? 악기를 파괴하지 않으면 되살아날 수 있는 것 아닌가?","JPN":"逃走した亡霊たちは？　楽器を破壊しないかぎり、また蘇るのではないか？","ENG":"What about the runaway ghosts? Won't they come back to life if the instruments are not destroyed?","TWN":"逃走的鬼魂呢？如果樂器沒有被破壞的話，不是還能復活嗎？"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇지, 총사대장님. 끈질기게 살아남아서 후환을 만드는 녀석들이니까.","JPN":"そうね、銃士隊長。しつこく生き残って後々の悩みの種になるやつらだから。","ENG":"That’s right, General Musketeer. They'll come back feistier than ever.","TWN":"是的，隊長。因為她們總是能頑強地生存下去，然後製造麻煩。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"셰나는 그쪽이 제대로 한 방 먹여 줬는데…….","JPN":"シェナにはそっちが一発食らわしてやってたけど……","ENG":"Shena was severely damaged by you for sure…","TWN":"世娜被你狠狠地揍了一頓……"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"마에스트로도 확실히 타격을 입었을 겁니다.","JPN":"マエストロも確かなダメージを受けたことでしょう。","ENG":"Maestra must have taken heavy damage as well.","TWN":"指揮家肯定也受到了打擊。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"빠져나갔지만 이 곳은 섬입니다. 추격한다면 금방 뒤쫓을 수 있겠죠.","JPN":"逃げはしましたが、ここは島です。追撃すればすぐ追いつくでしょう。","ENG":"Although they’ve slipped through our grasp, this is an island. If we track them down, we’ll be able to catch them in no time.","TWN":"雖然逃出去了，但這個地方是島嶼。如果去追，應該很快就能追上。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"잔향은 섬 밖을 가리키면서 사라졌도다.","JPN":"残響は島の外を示しては消えた。","ENG":"Remnants have faded out of the island.","TWN":"餘味指著島外消失了。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"하늘을 향한 창들이 요란한데 바다를 넘기에는 쉽지 아니할 터. 조력하는 자의 존재가 의심스럽구나.","JPN":"空に向かって放たれた数多くの槍をかわし海を越えるのはそう簡単ではあるまい。助力する者の存在が疑わしいぞ。","ENG":"With spears plunging towards the skies and waters too deep to cross, the helper comes as unknown.","TWN":"朝向天空的聲音如此吵雜，要想越過大海應該不容易吧。幫手的存在令人懷疑。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"잠깐. 우리 쪽은 이 이상 대규모로 부대가 움직이는 건 위험해.","JPN":"待って。私たちの方からこれ以上大規模に部隊を動かすのは危険だ。","ENG":"Wait. We can’t afford to move with a unit this large.","TWN":"等等，如果我們這邊再繼續大規模調動部隊就危險了。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이 곳도 행정상으로는 공해라서 출병이 가능했던 거야.","JPN":"ここも行政上は公海だったから出兵ができたんだ。","ENG":"It was only possible to come here because these waters don’t belong to anyone on paper.","TWN":"這裡也是因為行政上屬於公海，所以才能出兵。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"으음. 그렇다면 개인 자격으로 움직여야 하는 건가…….","JPN":"むむ。それなら個人で動くべきか……","ENG":"Hmm. Then that means I need to act as an individual from now on...","TWN":"嗯，那樣的話，我要以個人的身份行動嗎……"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"저희 역시, 지원 요청을 받고 움직이기는 했습니다만.","JPN":"私たちも支援要請を受けて動きはしましたが。","ENG":"We are also here because of the support request.","TWN":"雖然我們也是接到支援請求後行動的。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"본래는 정식으로 성무가 인정되어야 합니다.","JPN":"本来なら正式に聖務が認められなければなりません。","ENG":"But in principle, it should be permitted as a Sacred Mission for us to be able to dispatch.","TWN":"但原本應當是正式承認的聖務。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"이후에도 이런 식의 협력은 양측에게 불화를 일으키리라는 걸 명심해 주시길.","JPN":"以後、このような協力は双方に不和をもたらす可能性があるということを覚えておいてください。","ENG":"Please be notified that these urgent requests would be unbeneficial to both parties.","TWN":"希望以後你也能記得，這種方式的合作會給雙方帶來不和。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 면목 없군. 다음에 성당에 가면 반드시 신부님께 고해성사를 하겠네.","JPN":"はは、面目ない。今度聖堂に行った際は、必ず神父に告解しよう。","ENG":"Haha, apologies. I’ll make sure to confess the next time I visit church.","TWN":"哈哈，慚愧慚愧。下次去教堂，我一定會向神父懺悔的。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"중사님, 왜 그러십니까?","JPN":"軍曹、どうなさいましたか？","ENG":"Something wrong, Sergeant?","TWN":"中士，你怎麼了？"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};